import{_ as e,o,c as a,ag as s}from"./chunks/framework.DFmy_ALI.js";const p=JSON.parse('{"title":"OAuth and MCP Kill Switches","description":"","frontmatter":{},"headers":[],"relativePath":"guide/oauth-mcp-kill-switches.md","filePath":"guide/oauth-mcp-kill-switches.md"}'),n={name:"guide/oauth-mcp-kill-switches.md"};function d(l,t,c,i,r,h){return o(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="oauth-and-mcp-kill-switches" tabindex="-1">OAuth and MCP Kill Switches <a class="header-anchor" href="#oauth-and-mcp-kill-switches" aria-label="Permalink to &quot;OAuth and MCP Kill Switches&quot;">​</a></h1><p>OpenWave OAuth and Remote MCP are controlled by OpenWave Identity. Operators can turn access off globally, per environment, per owner type, per client, or per user grant.</p><h2 id="global-switches" tabindex="-1">Global switches <a class="header-anchor" href="#global-switches" aria-label="Permalink to &quot;Global switches&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Switch</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>oauth.global</code></td><td>off</td><td>Blocks token issuance and token introspection.</td></tr><tr><td><code>mcp.global</code></td><td>off</td><td>Blocks Remote MCP tool execution.</td></tr><tr><td><code>mcp.mutations</code></td><td>off</td><td>Blocks Remote MCP write tools even when a token has write scope.</td></tr><tr><td><code>environment.sandbox</code></td><td>on</td><td>Allows sandbox OAuth access.</td></tr><tr><td><code>environment.live</code></td><td>off</td><td>Allows live OAuth access.</td></tr><tr><td><code>owner.NEPTUNE</code></td><td>on</td><td>Allows Neptune owner clients.</td></tr><tr><td><code>owner.MERCHANT</code></td><td>off</td><td>Allows merchant clients.</td></tr><tr><td><code>owner.BANK</code></td><td>off</td><td>Allows bank clients.</td></tr><tr><td><code>owner.CUSTOMER</code></td><td>off</td><td>Allows customer delegated clients.</td></tr></tbody></table><h2 id="emergency-actions" tabindex="-1">Emergency actions <a class="header-anchor" href="#emergency-actions" aria-label="Permalink to &quot;Emergency actions&quot;">​</a></h2><p>Use the narrowest control that contains the issue:</p><ol><li>Disable a single client when one integration is compromised.</li><li>Revoke a user’s grants when delegated access is wrong.</li><li>Disable live access when production access must pause but sandbox can continue.</li><li>Disable <code>mcp.global</code> when agent access must stop immediately.</li><li>Disable <code>oauth.global</code> only when all OAuth access must stop.</li></ol><p>Existing raw merchant keys and portal sessions continue to work unless their separate controls are changed.</p><h2 id="audit" tabindex="-1">Audit <a class="header-anchor" href="#audit" aria-label="Permalink to &quot;Audit&quot;">​</a></h2><p>Every switch change, client suspension, secret rotation, token revocation, and user-grant revocation is written to the Identity portal audit log.</p><p>Remote MCP tool calls are also logged in Astro admin audit with the tool name and result status. Tool logs must not include API keys, OTPs, webhook secrets, raw national IDs, or full account numbers.</p>',11)])])}const m=e(n,[["render",d]]);export{p as __pageData,m as default};
